command:
const tableName = "Mystery Elements Table - Clues";

const table = game.tables.getName(tableName);

if (!table) {
  ui.notifications.error(`RollTable "${tableName}" not found.`);
  return;
}

// Ask for PP
const pp = await Dialog.prompt({
  title: "Power Points",
  content: `
  <form>
  <div class="form-group">
  <label>Enter PP Modifier:</label>
  <input type="number" name="pp" value="0"/>
  </div>
  </form>
  `,
  callback: html => Number(html.find('[name="pp"]').val())
});

// Roll 1d10
const baseRoll = await new Roll("1d10").evaluate();

// Final total
const total = baseRoll.total + pp;

// Create final roll object for table lookup
const finalRoll = await new Roll(`${total}`).evaluate();

// Draw from table
const draw = await table.draw({
  roll: finalRoll,
  displayChat: false
});

const result = draw.results[0];

// Chat output
let content = `
<h2>🔎 Mystery Clue</h2>

<p>
<strong>Roll:</strong> ${baseRoll.total}
+
<strong>PP:</strong> ${pp}
=
<strong>Total:</strong> ${total}
</p>

<p>
<strong>Table Result [${total}]:</strong> ${result.text}
</p>
`;

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
                   content: content
});
